package com.example.mpos.order;
import android.database.Cursor;import android.os.Bundle;import android.widget.TextView;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.database.DatabaseHelper;import com.example.mpos.utils.CurrencyUtils;
public class OrderDetailActivity extends AppCompatActivity{public void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_order_detail);long id=getIntent().getLongExtra("order_id",-1);StringBuilder s=new StringBuilder();Cursor o=new DatabaseHelper(this).getReadableDatabase().rawQuery("SELECT order_code,status,total_amount,channel FROM orders WHERE id=?",new String[]{String.valueOf(id)});try{if(o.moveToFirst())s.append(o.getString(0)).append("\n").append(o.getString(1)).append(" • ").append(o.getString(3)).append("\nTổng: ").append(CurrencyUtils.vnd(o.getLong(2))).append("\n\nSản phẩm\n");}finally{o.close();}Cursor it=new DatabaseHelper(this).getReadableDatabase().rawQuery("SELECT product_name,quantity,line_total FROM order_items WHERE order_id=?",new String[]{String.valueOf(id)});try{while(it.moveToNext())s.append(it.getString(0)).append(" × ").append(it.getInt(1)).append(" — ").append(CurrencyUtils.vnd(it.getLong(2))).append('\n');}finally{it.close();}((TextView)findViewById(R.id.txtOrderDetail)).setText(s);findViewById(R.id.btnBack).setOnClickListener(v->finish());}}
